args.command:
set -e
cd /workspace
cat > lib/plan_sync/contract.ex <<'EOF'
defmodule PlanSync.Contract do
  @moduledoc false

  @paid_plan_inputs ~w(team enterprise pro premium)

  def canonical_plan(plan) when plan in @paid_plan_inputs, do: :paid_team
  def canonical_plan(_plan), do: :free

  def billing_plan_code(:paid_team), do: ~s(premium)
  def billing_plan_code(:free), do: ~s(free)
  def billing_plan_code(plan), do: plan |> canonical_plan() |> billing_plan_code()

  def warehouse_plan_code(:paid_team), do: ~s(pro)
  def warehouse_plan_code(:free), do: ~s(free)
  def warehouse_plan_code(plan), do: plan |> canonical_plan() |> warehouse_plan_code()

  def amount_cents(:paid_team), do: 4900
  def amount_cents(:free), do: 0
  def amount_cents(plan), do: plan |> canonical_plan() |> amount_cents()

  def included_seats(:paid_team), do: 25
  def included_seats(:free), do: 1
  def included_seats(plan), do: plan |> canonical_plan() |> included_seats()

  def seat_band(:paid_team), do: ~s(multi)
  def seat_band(:free), do: ~s(single)
  def seat_band(plan), do: plan |> canonical_plan() |> seat_band()

  def billable?(:paid_team), do: true
  def billable?(:free), do: false
  def billable?(plan), do: plan |> canonical_plan() |> billable?()
end
EOF
cat > lib/plan_sync/billing_payload.ex <<'EOF'
defmodule PlanSync.BillingPayload do
  @moduledoc false

  alias PlanSync.Contract

  def build(attrs) do
    contract = attrs |> Map.fetch!(:plan) |> Contract.canonical_plan()

    %{
      customer: Map.fetch!(attrs, :customer),
      plan: Contract.billing_plan_code(contract),
      amount_cents: Contract.amount_cents(contract),
      included_seats: Contract.included_seats(contract)
    }
  end
end
EOF
